// Iteramos sobre todos los items que lleguen del nodo anterior
return $input.all().map(item => {
  const data = item.json;

  // Extraemos las nuevas variables (ajustadas a tu nuevo JSON)
  const f    = data.fecha;
  const tMax = data.temperature_2m_max;
  const tMin = data.temperature_2m_min;
  const at   = data.apparent_temperature_max; // Tomamos la sensación térmica máxima
  const r    = data.rain_sum;
  const sh   = data.showers_sum;
  const sn   = data.snowfall_sum;
  const p    = data.precipitation_sum; // Añadí precipitación total
  const ws   = data.wind_speed_10m_max;
  const wg   = data.wind_gusts_10m_max;

  // Construimos el string 'toon'
  // Nota: Quité H (humedad), CC (nubes) y D porque no vienen en tu nuevo JSON.
  // Añadí F (fecha), P (precipitación) y uní Tmax/Tmin.
  return {
    json: {
      toon: `[F:${f}|T:${tMax}/${tMin}|AT:${at}|P:${p}|R:${r}|SH:${sh}|SN:${sn}|WS:${ws}|WG:${wg}]`
    }
  };
});

const bogotaTime = new Date().toLocaleString("en-US", {
  timeZone: "America/Bogota",
  hour12: false
});

return [{
  json: {
    place: $('Webhook').first().json.body.place,
    temperature:$('Filtrar datos por fecha').first().json.temperature_2m_min + "/" + $('Filtrar datos por fecha').first().json.temperature_2m_max,
    weatherCondition:$input.first().json.content.parts[0].text,
    recommendedClothes:$('Message a model').first().json.content.parts[0].text ,
    windSpeed: $('Filtrar datos por fecha').first().json.wind_speed_10m_max,
    createdAt: bogotaTime
  }
}];

// 1. Tomamos los datos del nodo anterior
const data = $input.first().json;

// 2. Accedemos al objeto 'daily' que se ve en tu imagen
const daily = data.daily;

// Validamos que la información exista para evitar errores
if (!daily || !daily.time) {
  return [{ json: { error: "No se encontraron los datos de 'daily' o 'time'." } }];
}

const resultados = [];
const cantidadDias = daily.time.length;

// 3. Emparejamos los datos usando el índice 'i'
for (let i = 0; i < cantidadDias; i++) {
  resultados.push({
    json: {
      // Usamos el índice [i] para extraer el valor correspondiente de cada lista
      fecha: daily.time[i],
      temperature_2m_max: daily.temperature_2m_max ? daily.temperature_2m_max[i] : null,
      temperature_2m_min: daily.temperature_2m_min ? daily.temperature_2m_min[i] : null,
      apparent_temperature_max: daily.apparent_temperature_max ? daily.apparent_temperature_max[i] : null,
      apparent_temperature_min: daily.apparent_temperature_min ? daily.apparent_temperature_min[i] : null,
      rain_sum: daily.rain_sum ? daily.rain_sum[i] : null,
      showers_sum: daily.showers_sum ? daily.showers_sum[i] : null,
      snowfall_sum: daily.snowfall_sum ? daily.snowfall_sum[i] : null,
      precipitation_sum: daily.precipitation_sum ? daily.precipitation_sum[i] : null,
      wind_speed_10m_max: daily.wind_speed_10m_max ? daily.wind_speed_10m_max[i] : null,
      wind_gusts_10m_max: daily.wind_gusts_10m_max ? daily.wind_gusts_10m_max[i] : null
    }
  });
}

let item = 0;

for (let i = 0; i < resultados.length; i++) {
  if (resultados[i].json.fecha == $('Webhook').first().json.body.date) {
    item = i;
  }
}

return resultados[item];
